use crate::types::{DecideInput, DecideOutput};

fn realcompare(a: f64, b: f64) -> &'static str {
    if (a - b).abs() < 1e-9 {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x1 - x2).powi(2) + (y1 - y2).powi(2)).sqrt()
}

fn get_quadrant(x: f64, y: f64) -> usize {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x < 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

fn get_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()
}

fn get_angle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    let d12 = dist(x1, y1, x2, y2);
    let d23 = dist(x2, y2, x3, y3);
    let d13 = dist(x1, y1, x3, y3);
    if d12 == 0.0 || d23 == 0.0 {
        return None;
    }
    let cos_theta = (d12.powi(2) + d23.powi(2) - d13.powi(2)) / (2.0 * d12 * d23);
    let cos_theta_clamped = cos_theta.clamp(-1.0, 1.0);
    Some(cos_theta_clamped.acos())
}

fn can_be_contained_in_circle(
    x1: f64,
    y1: f64,
    x2: f64,
    y2: f64,
    x3: f64,
    y3: f64,
    radius: f64,
) -> bool {
    let a = x2 - x1;
    let b = y2 - y1;
    let c = x3 - x1;
    let d = y3 - y1;
    let e = a * (a + c) + b * (b + d);
    let f = c * (a + c) + d * (b + d);
    let g = 2.0 * (a * d - b * c);

    if g == 0.0 {
        let d12 = dist(x1, y1, x2, y2);
        let d23 = dist(x2, y2, x3, y3);
        let d13 = dist(x1, y1, x3, y3);
        let max_d = d12.max(d23).max(d13);
        return realcompare(max_d / 2.0, radius) != "GT";
    }

    let cx = (d * e - b * f) / g;
    let cy = (a * f - c * e) / g;
    let r = dist(x1, y1, cx + x1, cy + y1);
    realcompare(r, radius) != "GT"
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv = vec![false; 15];
    let n = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let p = &input.parameters;

    // LIC 1
    for i in 0..n - 1 {
        if realcompare(dist(x[i], y[i], x[i + 1], y[i + 1]), p.length1) == "GT" {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2
    for i in 0..n - 2 {
        if !can_be_contained_in_circle(
            x[i],
            y[i],
            x[i + 1],
            y[i + 1],
            x[i + 2],
            y[i + 2],
            p.radius1,
        ) {
            cmv[1] = true;
            break;
        }
    }

    // LIC 3
    for i in 0..n - 2 {
        if let Some(angle) = get_angle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]) {
            if realcompare(angle, std::f64::consts::PI - p.epsilon) == "LT"
                || realcompare(angle, std::f64::consts::PI + p.epsilon) == "GT"
            {
                cmv[2] = true;
                break;
            }
        }
    }

    // LIC 4
    for i in 0..n - 2 {
        if realcompare(
            get_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]),
            p.area1,
        ) == "GT"
        {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5
    for i in 0..=n - p.q_pts {
        let mut quads = std::collections::HashSet::new();
        for j in i..i + p.q_pts {
            quads.insert(get_quadrant(x[j], y[j]));
        }
        if quads.len() > p.quads {
            cmv[4] = true;
            break;
        }
    }

    // LIC 6
    for i in 0..n - 1 {
        if x[i + 1] - x[i] < 0.0 {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7
    if n >= 3 {
        for i in 0..=n - p.n_pts {
            let x1 = x[i];
            let y1 = y[i];
            let x2 = x[i + p.n_pts - 1];
            let y2 = y[i + p.n_pts - 1];
            let mut met = false;
            if x1 == x2 && y1 == y2 {
                for j in i + 1..i + p.n_pts - 1 {
                    if realcompare(dist(x1, y1, x[j], y[j]), p.dist) == "GT" {
                        met = true;
                        break;
                    }
                }
            } else {
                for j in i..i + p.n_pts {
                    let area = get_area(x1, y1, x2, y2, x[j], y[j]);
                    let line_len = dist(x1, y1, x2, y2);
                    let d = (2.0 * area) / line_len;
                    if realcompare(d, p.dist) == "GT" {
                        met = true;
                        break;
                    }
                }
            }
            if met {
                cmv[6] = true;
                break;
            }
        }
    }

    // LIC 8
    if n >= 3 {
        for i in 0..n - p.k_pts - 1 {
            if realcompare(
                dist(x[i], y[i], x[i + p.k_pts + 1], y[i + p.k_pts + 1]),
                p.length1,
            ) == "GT"
            {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9
    if n >= 5 {
        for i in 0..n - (p.a_pts + p.b_pts + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.a_pts + 1], y[i + p.a_pts + 1]);
            let p3 = (x[i + p.a_pts + p.b_pts + 2], y[i + p.a_pts + p.b_pts + 2]);
            if !can_be_contained_in_circle(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1, p.radius1) {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10
    if n >= 5 {
        for i in 0..n - (p.c_pts + p.d_pts + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.c_pts + 1], y[i + p.c_pts + 1]);
            let p3 = (x[i + p.c_pts + p.d_pts + 2], y[i + p.c_pts + p.d_pts + 2]);
            if let Some(angle) = get_angle(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1) {
                if realcompare(angle, std::f64::consts::PI - p.epsilon) == "LT"
                    || realcompare(angle, std::f64::consts::PI + p.epsilon) == "GT"
                {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11
    if n >= 5 {
        for i in 0..n - (p.e_pts + p.f_pts + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.e_pts + 1], y[i + p.e_pts + 1]);
            let p3 = (x[i + p.e_pts + p.f_pts + 2], y[i + p.e_pts + p.f_pts + 2]);
            if realcompare(get_area(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1), p.area1) == "GT" {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12
    if n >= 3 {
        for i in 0..n - p.g_pts - 1 {
            if x[i + p.g_pts + 1] - x[i] < 0.0 {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13
    if n >= 3 {
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - p.k_pts - 1 {
            let d = dist(x[i], y[i], x[i + p.k_pts + 1], y[i + p.k_pts + 1]);
            if realcompare(d, p.length1) == "GT" {
                part1 = true;
            }
            if realcompare(d, p.length2) == "LT" {
                part2 = true;
            }
        }
        cmv[12] = part1 && part2;
    }

    // LIC 14
    if n >= 5 {
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - (p.a_pts + p.b_pts + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.a_pts + 1], y[i + p.a_pts + 1]);
            let p3 = (x[i + p.a_pts + p.b_pts + 2], y[i + p.a_pts + p.b_pts + 2]);
            if !can_be_contained_in_circle(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1, p.radius1) {
                part1 = true;
            }
            if can_be_contained_in_circle(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1, p.radius2) {
                part2 = true;
            }
        }
        cmv[13] = part1 && part2;
    }

    // LIC 15
    if n >= 5 {
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - (p.e_pts + p.f_pts + 2) {
            let p1 = (x[i], y[i]);
            let p2 = (x[i + p.e_pts + 1], y[i + p.e_pts + 1]);
            let p3 = (x[i + p.e_pts + p.f_pts + 2], y[i + p.e_pts + p.f_pts + 2]);
            let area = get_area(p1.0, p1.1, p2.0, p2.1, p3.0, p3.1);
            if realcompare(area, p.area1) == "GT" {
                part1 = true;
            }
            if realcompare(area, p.area2) == "LT" {
                part2 = true;
            }
        }
        cmv[14] = part1 && part2;
    }

    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
        for j in 0..15 {
            if i == j {
                continue;
            }
            match input.lcm[i][j].as_str() {
                "NOTUSED" => pum[i][j] = true,
                "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                "ORR" => pum[i][j] = cmv[i] || cmv[j],
                _ => pum[i][j] = true,
            }
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }

    let mut launch = true;
    for i in 0..15 {
        if !fuv[i] {
            launch = false;
            break;
        }
    }

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
